static Document parseByteData(ByteBuffer byteData, String charsetName, String baseUri, Parser parser) {
    // Initialize variables
    String docData;
    Document doc = null;

    // Handle the case where charsetName is not specified
    if (charsetName == null) {
        // Decode using the default charset (assumed to be UTF-8) for initial parsing
        docData = Charset.forName(defaultCharset).decode(byteData).toString();
        doc = parser.parseInput(docData, baseUri);

        // Look for <meta> tags to potentially find a charset
        Element meta = doc.select("meta[http-equiv=content-type], meta[charset]").first();
        if (meta != null) {
            String foundCharset = meta.hasAttr("http-equiv") ? getCharsetFromContentType(meta.attr("content")) : meta.attr("charset");
            // Check if found charset is valid and different from default
            if (foundCharset != null && !foundCharset.isEmpty() && !foundCharset.equals(defaultCharset)) {
                charsetName = foundCharset;

                // Rewind ByteBuffer to start for re-decoding
                byteData.rewind();
                // Decode again with the found charset
                docData = Charset.forName(foundCharset).decode(byteData).toString();
                // Parse the document again
                doc = parser.parseInput(docData, baseUri);
            }
        }
    } else {
        // If charset is specified, validate and decode accordingly
        Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
        docData = Charset.forName(charsetName).decode(byteData).toString();
        doc = parser.parseInput(docData, baseUri);
    }

    // Set the output settings charset before returning
    if (doc != null) {
        doc.outputSettings().charset(charsetName);
    }

    return doc;
}
